#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* newNode(int v) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->val = v;
    n->left = n->right = NULL;
    return n;
}

int main() {
    int N; scanf("%d", &N);
    Node** nodes = (Node**)malloc((N+1)*sizeof(Node*));
    int* isChild = (int*)calloc(N+1, sizeof(int));
    for (int i=1;i<=N;i++) nodes[i]=newNode(i);
    for (int i=0;i<N-1;i++) {
        int p,c; char dir; scanf("%d %d %c", &p, &c, &dir);
        if (dir=='L') nodes[p]->left = nodes[c];
        else nodes[p]->right = nodes[c];
        isChild[c]=1;
    }
    int root=1; while (isChild[root]) root++;
    // BFS
    Node** q = (Node**)malloc((N+5)*sizeof(Node*));
    int front=0, rear=0;
    q[rear++] = nodes[root];
    while (front<rear) {
        int levelSize = rear - front;
        for (int i=0;i<levelSize;i++) {
            Node* cur = q[front++];
            printf("%d", cur->val);
            if (i+1<levelSize) printf(" ");
            if (cur->left) q[rear++] = cur->left;
            if (cur->right) q[rear++] = cur->right;
        }
        printf("\n");
    }
    free(nodes); free(isChild); free(q);
    return 0;
}

