import sys
from collections import deque

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    idx = 0
    N = int(data[idx].strip()); idx += 1
    nodes = [None] * (N + 1)
    for i in range(1, N + 1):
        nodes[i] = {'val': i, 'left': None, 'right': None}
    is_child = [False] * (N + 1)
    for _ in range(N - 1):
        p, c, d = data[idx].split(); idx += 1
        p = int(p); c = int(c)
        if d == 'L':
            nodes[p]['left'] = nodes[c]
        else:
            nodes[p]['right'] = nodes[c]
        is_child[c] = True
    root = 1
    while is_child[root]:
        root += 1
    q = deque([nodes[root]])
    while q:
        level = []
        for _ in range(len(q)):
            node = q.popleft()
            level.append(str(node['val']))
            if node['left']:
                q.append(node['left'])
            if node['right']:
                q.append(node['right'])
        print(' '.join(level))

if __name__ == "__main__":
    solve()

